code_body:
worker_processes 3;   
events { worker Connections 1024;   
}   
http { keepalive_timeout 60; upstream api Friendly feed { server 10.1.0.1:8080; server 10.1.0.2:8080; } upstream api friendly like { server 10.2.0.1:8081; server 10.2.0.1:8081; } upstream api friendly comment { server 10.3.0.1:8082; server 10.3.0.1:8082; } server { listen 80;

server_name apifriendly.com;   
location /feed { proxy_pass http://api Friendly feed; }   
location /like { proxy_pass http://api Friendly like; }   
location /comment { proxy_pass http://api Friendly comment; }

upstream backend {  
    server 192.168.1.5:80 weight=10;  
    server 192.168.1.6:81 weight=1;  
    server 192.168.1.7:82 weight=3;  
}
